Create DATABASE devwebcamp
on (name=devwebcamp_dat,filename='C:\devwebcamp\devwebcamp_mdf',size=5MB,maxsize=7GB,filegrowth=2MB)
LOG on
(name=devwebcamp_log,filename='C:\devwebcamp\devwebcamp_ldf',size=2MB,maxsize=800MB,filegrowth=1MB)

use devwebcamp

-- 1. Independent Tables
CREATE TABLE paquetes (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(30) NULL,
    PRIMARY KEY (id)
);

CREATE TABLE categorias (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(45) NULL,
    PRIMARY KEY (id)
);

CREATE TABLE dias (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(15) NULL,
    PRIMARY KEY (id)
);

CREATE TABLE horas (
    id INT NOT NULL IDENTITY(1,1),
    hora NVARCHAR(13) NULL,
    PRIMARY KEY (id)
);

CREATE TABLE regalos (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(50) NULL,
    PRIMARY KEY (id)
);

-- 2. User and Authentication Tables
CREATE TABLE usuarios (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(40) NULL,
    apellido NVARCHAR(40) NULL,
    email NVARCHAR(40) NULL,
    password NVARCHAR(60) NULL,
    confirmado BIT NULL,
    token NVARCHAR(13) NULL,
    admin BIT NULL,
    PRIMARY KEY (id)
);

-- 3. Speakers Table
CREATE TABLE ponentes (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(40) NULL,
    apellido NVARCHAR(40) NULL,
    ciudad NVARCHAR(20) NULL,
    pais NVARCHAR(20) NULL,
    imagen NVARCHAR(32) NULL,
    tags NVARCHAR(120) NULL,
    redes NVARCHAR(MAX) NULL,
    PRIMARY KEY (id)
);

-- 4. Registrations and Related Tables
CREATE TABLE registros (
    id INT NOT NULL IDENTITY(1,1),
    paquete_id INT NULL,
    pago_id NVARCHAR(30) NULL,
    token NVARCHAR(8) NULL,
    usuario_id INT NULL,
    regalo_id INT NULL,
    PRIMARY KEY (id),
    FOREIGN KEY (usuario_id) REFERENCES usuarios (id),
    FOREIGN KEY (paquete_id) REFERENCES paquetes (id),
    FOREIGN KEY (regalo_id) REFERENCES regalos (id)
);

-- 5. Events and Related Tables
CREATE TABLE eventos (
    id INT NOT NULL IDENTITY(1,1),
    nombre NVARCHAR(120) NULL,
    descripcion NVARCHAR(MAX) NULL,
    disponibles INT NULL,
    categoria_id INT NOT NULL,
    dia_id INT NOT NULL,
    hora_id INT NOT NULL,
    ponente_id INT NOT NULL,
    PRIMARY KEY (id),
    FOREIGN KEY (categoria_id) REFERENCES categorias (id),
    FOREIGN KEY (dia_id) REFERENCES dias (id),
    FOREIGN KEY (hora_id) REFERENCES horas (id),
    FOREIGN KEY (ponente_id) REFERENCES ponentes (id)
);

CREATE TABLE eventos_registros (
    id INT NOT NULL IDENTITY(1,1),
    evento_id INT NULL,
    registro_id INT NULL,
    PRIMARY KEY (id),
    FOREIGN KEY (evento_id) REFERENCES eventos (id),
    FOREIGN KEY (registro_id) REFERENCES registros (id)
);

